object Networking {

    private const val BASE_URL_DEV = "https://api.example.com/"
    private const val BASE_URL_STAGING = "https://api.staging.example.com/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/"

    private var client: OkHttpClient = OkHttpClient.Builder().build()
    private var gson: Gson = Gson()

    private var retrofit: Retrofit = Retrofit.Builder()
        .baseUrl(BASE_URL_DEV)
        .client(client)
        .addConverterFactory(GsonConverterFactory.create(gson))
        .build()

    val apiService: ApiService = retrofit.create(ApiService::class.java)

    fun setEnvironment(environment: String) {
        when (environment) {
            "dev" -> retrofit = retrofit.newBuilder().baseUrl(BASE_URL_DEV).build()
            "staging" -> retrofit = retrofit.newBuilder().baseUrl(BASE_URL_STAGING).build()
            "production" -> retrofit = retrofit.newBuilder().baseUrl(BASE_URL_PRODUCTION).build()
        }
    }
}

